    def test_account_becomes_restricted_exactly_after_365_days(
        self, kyc_service, account_service
    ):
        """Account should transition to restricted the moment the 365-day window elapses."""
        refresh_date = datetime(2023, 1, 1)
        customer = Customer(
            id="CUST-ROLL-01",
            name="Henry Ford",
            last_kyc_refresh=refresh_date,
        )
        account = Account(id="ACC-ROLL-01", customer=customer)

        # Day 365 — still compliant
        with freeze_time(refresh_date + timedelta(days=365)):
            account_service.evaluate_restriction(account)
            assert account.restricted is False

        # Day 366 — now expired
        with freeze_time(refresh_date + timedelta(days=366)):
            account_service.evaluate_restriction(account)
            assert account.restricted is True

    def test_kyc_validity_resets_correctly_after_refresh(
        self, kyc_service
    ):
        """After a refresh, the 365-day clock should restart from the new refresh date."""
        original_refresh = datetime(2022, 6, 15)
        new_refresh = datetime(2023, 6, 15)

        customer = Customer(
            id="CUST-ROLL-02",
            name="Ida Lovelace",
            last_kyc_refresh=original_refresh,
        )

        # Before refresh: check that original expiry is correct
        original_expiry = original_refresh + timedelta(days=KYC_REFRESH_DAYS)
        assert kyc_service.get_expiry_date(customer) == original_expiry

        # Perform refresh
        with freeze_time(new_refresh):
            kyc_service.record_refresh(customer, refresh_date=new_refresh)

        # After refresh: expiry clock restarts
        new_expiry = new_refresh + timedelta(days=KYC_REFRESH_DAYS)
        assert kyc_service.get_expiry_date(customer) == new_expiry

    def test_leap_year_does_not_break_365_day_window(self, kyc_service):
        """Ensure 365-day calculation is correct across a leap year boundary."""
        refresh_date = datetime(2023, 3, 1)  # year before leap year
        customer = Customer(
            id="CUST-LEAP",
            name="Jules Verne",
            last_kyc_refresh=refresh_date,
        )
        expected_expiry = refresh_date + timedelta(days=365)

        with freeze_time(expected_expiry):
            assert kyc_service.is_kyc_valid(customer) is True

        with freeze_time(expected_expiry + timedelta(days=1)):
            assert kyc_service.is_kyc_valid(customer) is False


