        txn = Transaction(
            id="TXN-NEG-001",
            account=expired_account,
            transaction_type=TransactionType.INBOUND,
            amount=-100.00,
        )
        with pytest.raises(ValueError, match="amount"):
            transaction_service.process(txn)

    @freeze_time(BASE_DATE)
    def test_processing_transaction_on_nonexistent_account_raises_error(
        self, transaction_service
    ):
        """A transaction referencing an unknown account should raise an error."""
        txn = Transaction(
            id="TXN-GHOST",
            account=None,
            transaction_type=TransactionType.INBOUND,
            amount=100.00,
        )
        with pytest.raises((ValueError, AccountRestrictedError, AttributeError)):
            transaction_service.process(txn)

    @freeze_time(BASE_DATE)
    def test_kyc_refresh_for_unknown_customer_raises_error(
        self, kyc_service
    ):
        """Attempting to refresh KYC for a None/unknown customer should raise an error."""
        with pytest.raises((ValueError, TypeError, AttributeError)):
            kyc_service.record_refresh(None, refresh_date=BASE_DATE)

    @freeze_time(BASE_DATE)
    def test_restriction_evaluation_on_account_with_no_customer_raises_error(
        self, account_service
    ):
        """Evaluating restriction on an account with no linked customer should raise an error."""
        account = Account(id="ACC-ORPHAN", customer=None)
        with pytest.raises((ValueError, AttributeError)):
            account_service.evaluate_restriction(account)

    @freeze_time(BASE_DATE)
    def test_concurrent_inbound_transactions_all_succeed_on_restricted_account(
        self, transaction_service, expired_account
    ):
        """Multiple sequential inbound transactions should all succeed on restricted accounts."""
        results = []
        for i in range(5):
            txn = Transaction(
                id=f"TXN-CONC-{i}",
                account=expired_account,
                transaction_type=TransactionType.INBOUND,
                amount=100.00 * (i + 1),
            )
            results.append(transaction_service.process(txn))
        assert all(r.success for r in results)
